package main

import "fmt"

func main() {
    // Slice literal
    nums := []int{10, 20, 30, 40, 50}
    fmt.Println("nums:", nums)
    fmt.Println("len:", len(nums), "cap:", cap(nums))

    // Re-slicing
    sub := nums[1:4]
    fmt.Println("sub[1:4]:", sub)

    // Slices share underlying array
    sub[0] = 99
    fmt.Println("nums after sub change:", nums)

    var nilSlice []int
    fmt.Println("nil slice:", nilSlice, "len:", len(nilSlice))
}
